@Configuration
class SecurityConfig {
    @Bean
    SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf.ignoringRequestMatchers("/saml/acs"))
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/", "/saml/acs", "/error").permitAll()
                .anyRequest().authenticated()
            )
            .formLogin(form -> form.disable())
            .httpBasic(Customizer.withDefaults())
            .logout(logout -> logout.logoutSuccessUrl("/"));
        return http.build();
    }
}

@Controller
class HomeController {
    @GetMapping("/")
    public ResponseEntity<String> home(HttpServletRequest request) {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        StringBuilder sb = new StringBuilder();
        sb.append("SAML SP Home\n");
        if (authentication != null && authentication.isAuthenticated() && !(authentication instanceof org.springframework.security.authentication.AnonymousAuthenticationToken)) {
            sb.append("Authenticated user: ").append(authentication.getName()).append("\n");
            HttpSession session = request.getSession(false);
            if (session != null) {
                Object attrs = session.getAttribute("SAML_ATTRIBUTES");
                sb.append("Session ID: ").append(session.getId()).append("\n");
                sb.append("Attributes: ").append(String.valueOf(attrs)).append("\n");
            }
        } else {
            sb.append("Not authenticated\n");
        }
        return ResponseEntity.ok(sb.toString());
    }

    @GetMapping("/me")
    public ResponseEntity<Map<String, Object>> me(HttpServletRequest request) {
        Map<String, Object> result = new HashMap<>();
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        result.put("authenticated", authentication != null && authentication.isAuthenticated() && !(authentication instanceof org.springframework.security.authentication.AnonymousAuthenticationToken));
        result.put("name", authentication != null ? authentication.getName() : null);
        HttpSession session = request.getSession(false);
        if (session != null) {
            result.put("sessionId", session.getId());
            result.put("attributes", session.getAttribute("SAML_ATTRIBUTES"));
            Map<String, Object> sessionAttrs = new HashMap<>();
            Enumeration<String> names = session.getAttributeNames();
            while (names.hasMoreElements()) {
                String name = names.nextElement();
                sessionAttrs.put(name, session.getAttribute(name));
            }
            result.put("session", sessionAttrs);
        }
        return ResponseEntity.ok(result);
    }
}

@Controller
class SamlAcsController {
    private final SamlResponseProcessor samlResponseProcessor;

    SamlAcsController(SamlResponseProcessor samlResponseProcessor) {
        this.samlResponseProcessor = samlResponseProcessor;
    }

    @PostMapping("/saml/acs")
    public ResponseEntity<?> assertionConsumerService(
        @RequestParam(name = "SAMLResponse", required = false) String samlResponse,
        HttpServletRequest request,
        HttpServletResponse response
    ) {
        if (!StringUtils.hasText(samlResponse)) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).body("Missing SAMLResponse");
        }

        try {
            SamlPrincipal principal = samlResponseProcessor.process(samlResponse);

            SamlAuthenticationToken authentication = new SamlAuthenticationToken(
                principal,
                principal.getAuthorities()
            );
            authentication.setAuthenticated(true);

            SecurityContext context = SecurityContextHolder.createEmptyContext();
            context.setAuthentication(authentication);
            SecurityContextHolder.setContext(context);

            HttpSession session = request.getSession(true);
            session.invalidate();
            session = request.getSession(true);

            session.setAttribute("SAML_NAME_ID", principal.getName());
            session.setAttribute("SAML_SESSION_INDEX", principal.getSessionIndex());
            session.setAttribute("SAML_ASSERTION_ID", principal.getAssertionId());
            session.setAttribute("SAML_RESPONSE_ID", principal.getResponseId());
            session.setAttribute("SAML_ISSUER", principal.getIssuer());
            session.setAttribute("SAML_ATTRIBUTES", principal.getAttributes());
            session.setAttribute("SAML_AUTHENTICATED_AT", Instant.now().toString());

            session.setAttribute(
                HttpSessionSecurityContextRepository.SPRING_SECURITY_CONTEXT_KEY,
                context
            );

            return ResponseEntity.ok("SAML authentication successful for " + principal.getName());
        } catch (Exception e) {
            SecurityContextHolder.clearContext();
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("SAML processing failed: " + e.getMessage());
        }
    }
}

@Component
class SamlResponseProcessor {
    public SamlPrincipal process(String base64SamlResponse) throws Exception {
        byte[] decoded = Base64.getDecoder().decode(base64SamlResponse);
        Document document = parseXmlSecurely(decoded);

        Element responseElement = document.getDocumentElement();
        if (responseElement == null || !"Response".equals(localName(responseElement))) {
            throw new IllegalArgumentException("Invalid SAML Response document");
        }

        String responseId = responseElement.getAttribute("ID");
        String issuer = firstElementText(document, "Issuer");
        Element assertion = firstElement(document, "Assertion");
        if (assertion == null) {
            throw new IllegalArgumentException("No Assertion found");
        }

        String assertionId = assertion.getAttribute("ID");
        String nameId = extractNameId(assertion);
        if (!StringUtils.hasText(nameId)) {
            throw new IllegalArgumentException("No NameID found");
        }

        String sessionIndex = extractSessionIndex(assertion);
        Map<String, List<String>> attributes = extractAttributes(assertion);

        List<SimpleGrantedAuthority> authorities = new ArrayList<>();
        List<String> roles = attributes.getOrDefault("roles", Collections.emptyList());
        if (roles.isEmpty()) {
            roles = attributes.getOrDefault("Role", Collections.emptyList());
        }
        if (roles.isEmpty()) {
            authorities.add(new SimpleGrantedAuthority("ROLE_USER"));
        } else {
            for (String role : roles) {
                String normalized = role.startsWith("ROLE_") ? role : "ROLE_" + role.toUpperCase().replace('-', '_').replace(' ', '_');
                authorities.add(new SimpleGrantedAuthority(normalized));
            }
        }

        return new SamlPrincipal(
            nameId,
            responseId,
            assertionId,
            issuer,
            sessionIndex,
            attributes,
            authorities
        );
    }

    private Document parseXmlSecurely(byte[] xmlBytes) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");
        DocumentBuilder builder = factory.newDocumentBuilder();
        return builder.parse(new ByteArrayInputStream(xmlBytes));
    }

    private String extractNameId(Element assertion) {
        Element subject = firstChildElement(assertion, "Subject");
        if (subject == null) {
            return null;
        }
        Element nameId = firstChildElement(subject, "NameID");
        return nameId != null ? trimToNull(nameId.getTextContent()) : null;
    }

    private String extractSessionIndex(Element assertion) {
        Element authnStatement = firstChildElement(assertion, "AuthnStatement");
        if (authnStatement == null) {
            return UUID.randomUUID().toString();
        }
        String sessionIndex = authnStatement.getAttribute("SessionIndex");
        return StringUtils.hasText(sessionIndex) ? sessionIndex : UUID.randomUUID().toString();
    }

    private Map<String, List<String>> extractAttributes(Element assertion) {
        Map<String, List<String>> attributes = new HashMap<>();
        Element attributeStatement = firstChildElement(assertion, "AttributeStatement");
        if (attributeStatement == null) {
            return attributes;
        }

        for (Node child = attributeStatement.getFirstChild(); child != null; child = child.getNextSibling()) {
            if (child.getNodeType() != Node.ELEMENT_NODE) {
                continue;
            }
            Element attr = (Element) child;
            if (!"Attribute".equals(localName(attr))) {
                continue;
            }
            String name = attr.getAttribute("Name");
            if (!StringUtils.hasText(name)) {
                name = attr.getAttribute("FriendlyName");
            }
            if (!StringUtils.hasText(name)) {
                continue;
            }

            List<String> values = new ArrayList<>();
            for (Node valueNode = attr.getFirstChild(); valueNode != null; valueNode = valueNode.getNextSibling()) {
                if (valueNode.getNodeType() != Node.ELEMENT_NODE) {
                    continue;
                }
                Element valueElement = (Element) valueNode;
                if ("AttributeValue".equals(localName(valueElement))) {
                    String value = trimToNull(valueElement.getTextContent());
                    if (value != null) {
                        values.add(value);
                    }
                }
            }
            attributes.put(name, values);
        }

        return attributes;
    }

    private Element firstElement(Document document, String localName) {
        return firstElement(document.getDocumentElement(), localName);
    }

    private Element firstElement(Element root, String wantedLocalName) {
        if (root == null) {
            return null;
        }
        if (wantedLocalName.equals(localName(root))) {
            return root;
        }
        for (Node child = root.getFirstChild(); child != null; child = child.getNextSibling()) {
            if (child.getNodeType() != Node.ELEMENT_NODE) {
                continue;
            }
            Element found = firstElement((Element) child, wantedLocalName);
            if (found != null) {
                return found;
            }
        }
        return null;
    }

    private String firstElementText(Document document, String localName) {
        Element element = firstElement(document, localName);
        return element != null ? trimToNull(element.getTextContent()) : null;
    }

    private Element firstChildElement(Element parent, String wantedLocalName) {
        if (parent == null) {
            return null;
        }
        for (Node child = parent.getFirstChild(); child != null; child = child.getNextSibling()) {
            if (child.getNodeType() == Node.ELEMENT_NODE && wantedLocalName.equals(localName(child))) {
                return (Element) child;
            }
        }
        return null;
    }

    private String localName(Node node) {
        return node.getLocalName() != null ? node.getLocalName() : node.getNodeName();
    }

    private String trimToNull(String value) {
        if (value == null) {
            return null;
        }
        String trimmed = value.trim();
        return trimmed.isEmpty() ? null : trimmed;
    }
}

class SamlAuthenticationToken extends AbstractAuthenticationToken {
    private final SamlPrincipal principal;

    SamlAuthenticationToken(SamlPrincipal principal, Collection<SimpleGrantedAuthority> authorities) {
        super(authorities);
        this.principal = principal;
        setDetails(principal.getAttributes());
    }

    @Override
    public Object getCredentials() {
        return "";
    }

    @Override
    public SamlPrincipal getPrincipal() {
        return principal;
    }

    @Override
    public String getName() {
        return principal.getName();
    }
}

